const now = new Date();
const options = { timeZone: 'America/Santiago' };
const hora = now.toLocaleTimeString('es-CL', options);
const fecha = now.toLocaleDateString('es-CL', options);
const dia = now.getDate();
const multaActiva = dia > 10;
const diasParaVencimiento = multaActiva ? 0 : (10 - dia);
const h = now.getHours();
const turno = h >= 8 && h < 16 ? 'Mañana (08:00-16:00)' : h >= 16 && h < 24 ? 'Tarde (16:00-00:00)' : 'Noche (00:00-08:00)';
const estadoSistema = { chatbot: 'activo', baseDatos: 'conectada', apiUF: 'disponible', guardrails: 'activos' };
const proximoVencimiento = new Date(now.getFullYear(), now.getMonth() + (dia > 10 ? 1 : 0), 10);
const diasRestantes = Math.ceil((proximoVencimiento - now) / (1000 * 60 * 60 * 24));
return [{ json: { sistema: 'Comunidad Segura v1.0', estado: 'operativo', timestamp: now.toISOString(), fecha, hora, turnoConserje: turno, gastosComunes: { multaActiva, diasParaVencimiento, proximoVencimiento: proximoVencimiento.toLocaleDateString('es-CL'), diasHastaVencimiento: diasRestantes }, reglas: { anticipacionReservas: '48 horas', slaUrgente: '24 horas', multaPorAtraso: '1.5%' }, servicios: estadoSistema }}];

