const d = $input.first().json;
const now = new Date();
const dia = now.getDate();
const multaActiva = dia > 10;
const h = now.getHours();
const turno = h >= 8 && h < 16 ? 'mañana' : h >= 16 ? 'tarde' : 'noche';
const alertas = [];
if (Number(d.tickets_urgentes) > 0) alertas.push({ tipo: 'urgente', mensaje: `${d.tickets_urgentes} ticket(s) urgente(s) pendiente(s)` });
if (multaActiva) alertas.push({ tipo: 'multa', mensaje: 'Período de multa activo (día > 10)' });
if (Number(d.reclamos_pendientes) > 3) alertas.push({ tipo: 'reclamos', mensaje: `${d.reclamos_pendientes} reclamos sin atender` });
return [{ json: { ...d, alertas, turnoConserje: turno, multaGastosActiva: multaActiva, timestamp: now.toISOString() }}];
